from dataclasses import dataclass, field
from typing import Iterator, Iterable, Callable, List, Optional

import numpy as np
import numpy.typing as npt

from geosat.cloud import PointCloud, pyvoxels
from geosat.cloud.pyvoxels import cube_window, adjacency_dict_of_voxels, VoxelDict3D
from geosat.cloud.tiles import (
    Coords2D,
    TileCoords2D,
    TileCoord,
    PointIndices,
    PaddedTiler,
)


class CloudExtractor:
    """Extract single objects of a class in a point cloud"""

    def __init__(self, cloud: PointCloud, k: float) -> None:
        """
        :param cloud: The point cloud to process
        :param k: Coefficient giving the size of the voxels
            (smaller => better precision)
        """
        self.cloud = cloud
        self.k = k

    def _compute_voxels(self, whitelist: Optional[Iterable[int]] = None) -> VoxelDict3D:
        """Generate a dictionary of voxels

        :param whitelist: The classification code used to filter points,
            only points of the specified code will be considered

        :return: Voxels dictionary where keys are voxel coordinates and values are
            list of indexes of points belonging the voxel
        """
        if whitelist is None:
            return pyvoxels.voxelize_cloud(self.cloud, self.k)
        else:
            return pyvoxels.voxelize_cloud(
                self.cloud,
                self.k,
                mask=np.isin(self.cloud.classification, list(whitelist)),
            )

    def _segment_voxels(
        self, whitelist: Optional[Iterable[int]] = None
    ) -> List[List[int]]:
        """Create a list of points for each single object using voxels

        :param whitelist: The classification code used to filter points,
            only points of the specified codes will be considered. If ``None``,
            all points are considered

        :return: A list of points indices for each segmented object
        """
        voxels = self._compute_voxels(whitelist=whitelist)

        adjacency_dict = adjacency_dict_of_voxels(voxels)

        labels_voxels = pyvoxels.labelize_voxels(adjacency_dict)
        list_of_points_per_label = pyvoxels.get_points_of_voxels_labels(
            labels_voxels, voxels
        )
        return list_of_points_per_label

    def extract_cloud_objects(
        self, code: int, min_points_count: int = 1000
    ) -> List[List[int]]:
        """Return a list of point indices for each of the single object found in the
        point cloud.

        :param code: Classification of the points to be considered
        :param min_points_count: Minimum number of points that the object
            must have to be considered as one

        :return: List of point indices corresponding to the objects
        """
        objects = self._segment_voxels(whitelist={code})

        return [points for points in objects if len(points) >= min_points_count]

    def filter_small_object(
        self, min_size: int, whitelist: Optional[Iterable[int]] = None
    ) -> List[int]:
        objects = self._segment_voxels(whitelist=whitelist)
        small_objects_points = (points for points in objects if len(points) <= min_size)
        return [index for points in small_objects_points for index in points]


@dataclass
class CenteredExtractor:
    """
    :param centers: The 2D positions of centers where sub clouds should be located
    :param window_size: The side length of extracted sub clouds
    """

    centers: Coords2D
    window_size: float
    _tiler: PaddedTiler = field(init=False)

    def __post_init__(self) -> None:
        origin = np.mean(self.centers, axis=0)
        self._tiler = PaddedTiler(origin, self.window_size)

    @staticmethod
    def _get_near_tiles(tile_coord: TileCoord) -> TileCoords2D:
        return cube_window(tile_coord)

    def _are_nearby_point(
        self, point_coord: npt.NDArray[np.float64], coords: Coords2D
    ) -> npt.NDArray[np.bool_]:
        """
        :return: Array of boolean that represents coordinates within ``coords``
            that are nearby the ``point_coord``.
        """
        radius_vector = np.array([self.window_size / 2, self.window_size / 2])
        mins = point_coord - radius_vector
        maxes = point_coord + radius_vector
        return np.logical_and(
            np.all(mins <= coords, axis=1), np.all(coords < maxes, axis=1)
        )

    def extract(self, coords: Coords2D) -> Iterator[PointIndices]:
        """Extract sub-clouds from cubic bounding boxes centered on point coordinates

        :param coords: a numpy array of 2D point coordinates, often extracted from
            x and y fields from a `PointCloud`
        :return: an iterator of point clouds for each coordinate within ``self.centers``
        """
        # The voxel grid has a resolution of the same order of magnitude as the windows
        tiles_and_coord_indices = {
            point_indices.coord: point_indices.indices
            for point_indices in self._tiler.generate_tiles(coords)
        }

        for center in self.centers:
            center_tile = self._tiler.compute_tile_coords(center.reshape((1, -1)))
            center_x, center_y = center_tile[0]
            nearby_tiles = self._tiler.get_near_tiles((center_x, center_y))
            tiles = np.r_[nearby_tiles, center_tile]
            selected_indices = np.concatenate(
                [
                    tiles_and_coord_indices.get((x, y), np.array([])).astype(np.int64)
                    for (x, y) in tiles
                ]
            )
            selected_coords = coords[selected_indices]
            coord_indices_within_radius = selected_indices[
                self._are_nearby_point(
                    center,  # type: ignore[arg-type]
                    selected_coords,
                )
            ]
            yield coord_indices_within_radius


def default_cloud_mapping(cloud: PointCloud, coords: Coords2D) -> List[int]:
    """
    :param cloud: Cloud that *could* contain coordinates within ``coords`` array
    :param coords: Array of N coordinates with shape [N, 2 or 3].
    :return: List of indices of ``coords`` contained within the cloud extent
    """
    mins = cloud.bb_min()[:2]
    maxes = cloud.bb_max()[:2]
    return list(
        np.flatnonzero(
            np.logical_and(
                np.all(mins <= coords, axis=1), np.all(coords < maxes, axis=1)
            )
        )
    )


def extract_sub_clouds(
    coords: Coords2D,
    clouds: Iterable[PointCloud],
    window_size: float,
    mapping_func: Callable[
        [PointCloud, npt.NDArray], List[int]
    ] = default_cloud_mapping,
) -> List[PointCloud]:
    """Extracts sub clouds of points within ``clouds`` centered around
    coordinates ``coords``

    :param coords: Array of shape [N, 2] of 2D coordinates of positions to
        extract sub clouds from ``clouds``
    :param clouds: An iterable of PointClouds that should be merged at
        each location around ``coords``
    :param window_size: Size the side of the extracted sub clouds
    :param mapping_func: Size the side of the extracted sub clouds
    :return: List of size N with a sub cloud centered around each coordinates
        of ``coords``, indices of this list are coherent with indices of each
        coordinates within ``coords``
    """

    sub_clouds_list: List[List[PointCloud]] = [[] for _ in range(coords.shape[0])]

    for cloud in clouds:
        contained_coord_indices = mapping_func(cloud, coords)
        extractor = CenteredExtractor(coords[contained_coord_indices], window_size)
        sub_cloud_indices = extractor.extract(cloud.coords[:, :2])
        for contained_coord_id, point_indices in enumerate(sub_cloud_indices):
            coord_id = contained_coord_indices[contained_coord_id]
            sub_clouds_list[coord_id].append(cloud[point_indices])

    return [PointCloud.merge(iter(sub_clouds)) for sub_clouds in sub_clouds_list]
